rubric.en:
Expected code/algorithm:
sort(out S) {
  P = lowermost(S);
  for (i=0; i < S.size(); ++i)
    for (j=i+1; j < S.size(); ++j)
      if (cmp(P, S[i], S[j]) == 1)
        swap(S, i, j);
}

